interface Flyable {
    void fly(); // Abstract by default
}
abstract class Vehicle {
    void start() { System.out.println("Engine started"); } // Shared logic
    abstract void steer(); // Must be implemented by child
}
class Drone extends Vehicle implements Flyable {
    void steer() { System.out.println("Using joysticks"); }
    public void fly() { System.out.println("Spinning rotors"); }
}

public void readFile(String path) {
    try {
        // Risky code
        FileReader reader = new FileReader(path);
    } catch (FileNotFoundException e) {
        // Handling the error gracefully
        System.err.println("File missing: " + e.getMessage());
    } finally {
        // Always executes, even if an exception occurs
        System.out.println("Cleanup resources");
    }
}

