// Create a thread pool with exactly 10 reusable threads
ExecutorService executor = Executors.newFixedThreadPool(10);

for (int i = 0; i < 1000; i++) {
    final int taskId = i;
    executor.submit(() -> {
        // 1000 tasks are efficiently processed by only 10 threads
        System.out.println("Processing task " + taskId + " on " + Thread.currentThread().getName());
    });
}
executor.shutdown(); // Gracefully stop accepting new tasks

class ServerControl {
    // Guarantees visibility across all CPU cores instantly
    private volatile boolean isRunning = true;

    public void stopServer() {
        isRunning = false; // Write is flushed to main memory
    }

    public void runServer() {
        while(isRunning) { 
            // Read is forced from main memory, avoiding infinite loops
            processRequests(); 
        }
    }
}

